payload.raw:
{
  "layout": "comparison",
  "title": "创新领域现状",
  "subtitle": "柔性传感与多模态交互技术路径对比",
  "left": {
    "heading": "本项目技术路径",
    "items": ["均致力于提升柔性传感与交互性能", "!全栈自研，突破高精度、低成本、自主可控核心瓶颈", "研发仿水膜-鱼网结构液态金属薄膜与低迟滞介质，结合光纤-IMU混合架构实现硬件级漂移抑制，目标精度0.1mm、延迟<20ms；开发轻量化手势识别模型，精度>97%；集成压力梯度与温控反馈模块，并与10余种国产设备无缝对接。"],
    "tone": "positive"
  },
  "right": {
    "heading": "当前技术现状",
    "items": ["均致力于提升柔性传感与交互性能", "!存在传感器成本高、算法框架封闭、国产平台接口缺失三重瓶颈", "柔性传感器迟滞误差高（>15%）、环境稳定性弱、制备成本高昂；手势识别模型在复杂工况下精度不足92%、延迟超80ms；多模态交互缺乏闭环设计，与国产XR平台深度适配方案稀缺，触觉反馈技术尚未实现高保真压力与动态温度的协同工程化应用。"],
    "tone": "negative"
  }
}

