{
  "layout": "milestone-list",
  "title": "创新设计",
  "subtitle": "项目实施计划",
  "events": [
    {
      "date": "第1-2月",
      "title": "硬件攻坚",
      "description": "完成传感器微结构设计、液态金属-聚氨酯复合材料制备与信号标定，构建0.1mm级分辨率的混合传感架构。配置2名硬件工程师与1名材料研究员，需柔性材料合成设备与高精度信号采集平台，预算22万元。"
    },
    {
      "date": "第3月",
      "title": "算法开发",
      "description": "开发轻量化手势识别分层模型，结合时序滑动窗口分割与噪声抑制，实现毫秒级实时推理与多模态融合协议栈。配置3名算法工程师与1名数据标注员，需GPU服务器（4×A100）与标注数据集，预算18万元。"
    },
    {
      "date": "第4月",
      "title": "系统集成",
      "description": "进行软硬件联调，嵌入压力/温度动态反馈执行单元，构建感知-意图-反馈闭环。配置2名全栈工程师与2名测试工程师，需多模态测试舱与合作设备接口（H-Box/眼镜），预算15万元。"
    },
    {
      "date": "第5-6月",
      "title": "场景验证优化",
      "description": "依托合作企业平台开展工业级远程操控、虚拟实训等多场景压力测试，进行用户体验迭代优化，形成可复用的交互标准接口。配置1名产品经理与2名场景测试员，需远程操控实训场地与用户反馈采集系统，预算15万元。"
    }
  ]
}

